import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const Profile = () => {
  const navigate = useNavigate();
  const userId = localStorage.getItem("userId");
  const token = localStorage.getItem("token");

  const [image, setImage] = useState("");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [bio, setBio] = useState("");

  // Redirect if not logged in
  useEffect(() => {
    if (!token) {
      navigate("/login");
    }
  }, [token, navigate]);

  // Load saved profile
  useEffect(() => {
    if (userId && token) {
      const data = JSON.parse(localStorage.getItem(`profile_${userId}`)) || {};
      setImage(data.image || "");
      setName(data.name || "");
      setEmail(data.email || localStorage.getItem("userEmail") || "");
      setBio(data.bio || "");
    }
  }, [userId, token]);

  const handleImage = (e) => {
    const file = e.target.files[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImage(reader.result);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (!userId) return;
    const data = { image, name, email, bio };
    localStorage.setItem(`profile_${userId}`, JSON.stringify(data));
    alert("Profile saved successfully");
  };

  const handleBack = () => {
    navigate(-1);
  };

  if (!token) {
    return null;
  }

  return (
    <div style={container}>
      {/* Back Button */}
      <button onClick={handleBack} style={backButton}>
        ← Back
      </button>

      <div style={content}>
        <h1 style={title}>Profile Settings</h1>

        {/* Profile Image */}
        <div style={imageSection}>
          <img
            src={image || "https://via.placeholder.com/120"}
            alt="Profile"
            style={avatar}
          />
          <label style={uploadButton}>
            Change Photo
            <input
              type="file"
              accept="image/*"
              onChange={handleImage}
              style={{ display: "none" }}
            />
          </label>
        </div>

        {/* Form */}
        <div style={form}>
          <div style={field}>
            <label style={label}>Full Name</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Enter your name"
              style={input}
            />
          </div>

          <div style={field}>
            <label style={label}>Email Address</label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              style={input}
              disabled
            />
          </div>

          <div style={field}>
            <label style={label}>Bio</label>
            <textarea
              value={bio}
              onChange={(e) => setBio(e.target.value)}
              placeholder="Tell us about yourself..."
              rows="4"
              style={textarea}
            />
          </div>

          <button onClick={handleSave} style={saveButton}>
            Save Changes
          </button>
        </div>
      </div>
    </div>
  );
};

// Professional Black/White/Gray Styles
const container = {
  minHeight: "100vh",
  width: "100%",
  background: "#f5f5f5",
  position: "relative",
};

const backButton = {
  position: "fixed",
  top: "20px",
  left: "20px",
  padding: "8px 16px",
  background: "#fff",
  color: "#333",
  border: "1px solid #e0e0e0",
  borderRadius: "6px",
  cursor: "pointer",
  fontSize: "14px",
  fontWeight: "500",
  transition: "all 0.2s",
  zIndex: 10,
};

const content = {
  maxWidth: "600px",
  margin: "0 auto",
  padding: "80px 24px 48px",
};

const title = {
  fontSize: "28px",
  fontWeight: "600",
  color: "#111",
  marginBottom: "32px",
  letterSpacing: "-0.5px",
};

const imageSection = {
  textAlign: "center",
  marginBottom: "32px",
};

const avatar = {
  width: "120px",
  height: "120px",
  borderRadius: "50%",
  objectFit: "cover",
  border: "3px solid #fff",
  boxShadow: "0 2px 8px rgba(0,0,0,0.1)",
  marginBottom: "12px",
};

const uploadButton = {
  display: "inline-block",
  padding: "6px 14px",
  background: "#fff",
  color: "#666",
  border: "1px solid #e0e0e0",
  borderRadius: "20px",
  cursor: "pointer",
  fontSize: "13px",
  transition: "all 0.2s",
};

const form = {
  background: "#fff",
  borderRadius: "12px",
  padding: "32px",
  boxShadow: "0 1px 3px rgba(0,0,0,0.05)",
  border: "1px solid #eaeaea",
};

const field = {
  marginBottom: "24px",
};

const label = {
  display: "block",
  fontSize: "13px",
  fontWeight: "500",
  color: "#666",
  marginBottom: "8px",
  textTransform: "uppercase",
  letterSpacing: "0.5px",
};

const input = {
  width: "100%",
  padding: "12px 16px",
  fontSize: "15px",
  border: "1px solid #e0e0e0",
  borderRadius: "8px",
  background: "#fff",
  color: "#333",
  outline: "none",
  transition: "border-color 0.2s",
  boxSizing: "border-box",
};

const textarea = {
  width: "100%",
  padding: "12px 16px",
  fontSize: "15px",
  border: "1px solid #e0e0e0",
  borderRadius: "8px",
  background: "#fff",
  color: "#333",
  outline: "none",
  resize: "vertical",
  fontFamily: "inherit",
  boxSizing: "border-box",
};

const saveButton = {
  width: "100%",
  padding: "12px",
  background: "#111",
  color: "#fff",
  border: "none",
  borderRadius: "8px",
  fontSize: "15px",
  fontWeight: "500",
  cursor: "pointer",
  transition: "background 0.2s",
  marginTop: "8px",
};

export default Profile;
